import React, { useState } from 'react';
import './RecentUsersTable.css';

interface UserData {
  id: number;
  name: string;
  planName: string;
  email: string;
  phone: string;
  status: 'Active' | 'Inactive' | 'Pending';
  joiningDate: string;
}

const RecentUsersTable: React.FC = () => {
  const [currentPage, setCurrentPage] = useState(1);
  const usersPerPage = 10;

  const users: UserData[] = [
    {
      id: 1,
      name: "Alexandra Deff",
      planName: "Premium Plan",
      email: "alex.deff@email.com",
      phone: "+1 (555) 123-4567",
      status: "Active",
      joiningDate: "Dec 15, 2024"
    },
    {
      id: 2,
      name: "Edwin Adenike",
      planName: "Basic Plan",
      email: "edwin.a@email.com",
      phone: "+1 (555) 234-5678",
      status: "Active",
      joiningDate: "Nov 28, 2024"
    },
    {
      id: 3,
      name: "Isaac Oluwatemiloun",
      planName: "Pro Plan",
      email: "isaac.o@email.com",
      phone: "+1 (555) 345-6789",
      status: "Pending",
      joiningDate: "Dec 20, 2024"
    },
    {
      id: 4,
      name: "David Oshodi",
      planName: "Premium Plan",
      email: "david.oshodi@email.com",
      phone: "+1 (555) 456-7890",
      status: "Inactive",
      joiningDate: "Oct 10, 2024"
    },
    {
      id: 5,
      name: "Sarah Johnson",
      planName: "Free Plan",
      email: "sarah.j@email.com",
      phone: "+1 (555) 567-8901",
      status: "Active",
      joiningDate: "Jan 05, 2025"
    },
    {
      id: 6,
      name: "Michael Chen",
      planName: "Premium Plan",
      email: "michael.chen@email.com",
      phone: "+1 (555) 678-9012",
      status: "Active",
      joiningDate: "Dec 18, 2024"
    },
    {
      id: 7,
      name: "Emily Rodriguez",
      planName: "Basic Plan",
      email: "emily.r@email.com",
      phone: "+1 (555) 789-0123",
      status: "Pending",
      joiningDate: "Jan 02, 2025"
    },
    {
      id: 8,
      name: "James Wilson",
      planName: "Pro Plan",
      email: "james.wilson@email.com",
      phone: "+1 (555) 890-1234",
      status: "Active",
      joiningDate: "Dec 22, 2024"
    },
    {
      id: 9,
      name: "Lisa Anderson",
      planName: "Premium Plan",
      email: "lisa.anderson@email.com",
      phone: "+1 (555) 901-2345",
      status: "Inactive",
      joiningDate: "Nov 15, 2024"
    },
    {
      id: 10,
      name: "Robert Taylor",
      planName: "Basic Plan",
      email: "robert.taylor@email.com",
      phone: "+1 (555) 012-3456",
      status: "Active",
      joiningDate: "Dec 25, 2024"
    },
    {
      id: 11,
      name: "Jennifer Davis",
      planName: "Free Plan",
      email: "jennifer.davis@email.com",
      phone: "+1 (555) 123-4567",
      status: "Pending",
      joiningDate: "Jan 08, 2025"
    },
    {
      id: 12,
      name: "Kevin Brown",
      planName: "Premium Plan",
      email: "kevin.brown@email.com",
      phone: "+1 (555) 234-5678",
      status: "Active",
      joiningDate: "Dec 30, 2024"
    },
    {
      id: 13,
      name: "Amanda Martinez",
      planName: "Pro Plan",
      email: "amanda.martinez@email.com",
      phone: "+1 (555) 345-6789",
      status: "Active",
      joiningDate: "Jan 10, 2025"
    },
    {
      id: 14,
      name: "Daniel Garcia",
      planName: "Basic Plan",
      email: "daniel.garcia@email.com",
      phone: "+1 (555) 456-7890",
      status: "Inactive",
      joiningDate: "Nov 20, 2024"
    },
    {
      id: 15,
      name: "Michelle Lee",
      planName: "Premium Plan",
      email: "michelle.lee@email.com",
      phone: "+1 (555) 567-8901",
      status: "Active",
      joiningDate: "Jan 12, 2025"
    }
  ];

  // Pagination
  const totalPages = Math.ceil(users.length / usersPerPage);
  const startIndex = (currentPage - 1) * usersPerPage;
  const endIndex = startIndex + usersPerPage;
  const currentUsers = users.slice(startIndex, endIndex);

  const renderPagination = () => {
    if (totalPages <= 1) return null;

    const pages = [];
    const maxVisiblePages = 5;
    let startPage = Math.max(1, currentPage - Math.floor(maxVisiblePages / 2));
    let endPage = Math.min(totalPages, startPage + maxVisiblePages - 1);

    if (endPage - startPage + 1 < maxVisiblePages) {
      startPage = Math.max(1, endPage - maxVisiblePages + 1);
    }

    // Previous button
    if (currentPage > 1) {
      pages.push(
        <button
          key="prev"
          className="pagination-btn"
          onClick={() => setCurrentPage(currentPage - 1)}
        >
          <img src="/Light-Icon/Iconly/Light-Outline/Arrow - Left.svg" alt="Previous" />
        </button>
      );
    }

    // Page numbers
    for (let i = startPage; i <= endPage; i++) {
      pages.push(
        <button
          key={i}
          className={`pagination-btn ${i === currentPage ? 'active' : ''}`}
          onClick={() => setCurrentPage(i)}
        >
          {i}
        </button>
      );
    }

    // Next button
    if (currentPage < totalPages) {
      pages.push(
        <button
          key="next"
          className="pagination-btn"
          onClick={() => setCurrentPage(currentPage + 1)}
        >
          <img src="/Light-Icon/Iconly/Light-Outline/Arrow - Right.svg" alt="Next" />
        </button>
      );
    }

    return pages;
  };

  return (
    <div className="recent-users-table">
      <div className="table-header-section">
        <h2>Recent Users</h2>
        <button className="view-all-btn">View All</button>
      </div>

      <div className="table-container">
        <table className="users-table">
          <thead>
            <tr>
              <th>User's Name</th>
              <th>Plan Name</th>
              <th>Contact Info</th>
              <th>Status</th>
              <th>Joining Date</th>
            </tr>
          </thead>
          <tbody>
            {currentUsers.map((user) => (
              <tr key={user.id}>
                <td>
                  <div className="user-cell">
                    <span className="user-name">{user.name}</span>
                  </div>
                </td>
                <td>
                  <span className="plan-name">{user.planName}</span>
                </td>
                <td>
                  <div className="contact-info">
                    <div className="email">{user.email}</div>
                    <div className="phone">{user.phone}</div>
                  </div>
                </td>
                <td>
                  <span className={`status-badge ${user.status.toLowerCase()}`}>
                    {user.status}
                  </span>
                </td>
                <td>
                  <span className="joining-date">{user.joiningDate}</span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {totalPages > 1 && (
        <div className="table-pagination">
          <div className="pagination-info">
            Showing {startIndex + 1}-{Math.min(endIndex, users.length)} of {users.length} users
          </div>
          <div className="pagination-controls">
            {renderPagination()}
          </div>
        </div>
      )}
    </div>
  );
};

export default RecentUsersTable;
